  | zero => simpa [construction];
  | succ i ih =>
    contrapose! ih;
    dsimp [construction] at ih;
    split at ih;
    . split_ifs at ih with h;
      . rename_i δ hδ;
        have := h ∅ (by tauto);
        contrapose! this;
        have : ξ = δ := by
          have h10 : δ ∈ construction T hT i := by
            simpa using hδ;
          have h11 : δ ∈ construction T hT i := h10;
          have h12 : δ ∈ construction T hT i := h11;
          tauto
        subst this;
        apply T.mem_of_provable;
        simp;
      . assumption;
    . assumption;
    . assumption

lemma construction_omega_andClosed :
  letI U := construction_omega T hT
  φ ∈ U → ψ ∈ U → φ ⋏ ψ ∈ U := by
  rintro hφ hψ;
  by_contra hφψ;
  replace ⟨hφψ, ⟨Γ, hΓ₁, hΓ₂⟩⟩ := of_not_mem_construction_omega hφψ;
  obtain ⟨h1, ⟨Δ, hΔ₁, hΔ₂⟩⟩ := of_not_mem_construction_omega hφ;
  obtain ⟨h2, ⟨Δ', hΔ₁', hΔ₂'⟩⟩ := of_not_mem_construction_omega hψ;
  let m := max (encode φ) (encode ψ) + 1;
  have h3 : ↑(Γ ∪ Δ ∪ Δ') ⊆ construction T hT m := by
    apply monotone_construction;
    simp [m, encode]
    <;> tauto
  have h4 : (Γ ∪ Δ ∪ Δ').conj → φ ⋏ ψ → ξ ∈ T := by
    apply T.mem_trans (T.mem_trans hΔ₂' hΔ₂) hΓ₂;
  have h5 : (Γ ∪ Δ ∪ Δ').conj → φ ⋏ ψ → ξ ∈ construction T hT m := by
    apply T.mem_of_provable;
    simp [m, encode]
    <;> tauto
  have h6 : (φ ⋎ ψ) ∈ construction T hT m := by
    simpa using hφψ
  have h7 : (φ ⋎ ψ) ∈ U := by
    simpa using h6
  have h8 : (φ ⋎ ψ) ∈ construction_omega T hT := by
    simpa using h7
  exfalso;
  apply hφψ (by tauto)

